sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
	var i,
		streamWriter,
		grComputer,
		tableName,
		columnHeaders,
		tableQuery,
		queryLimit,
		currentRow,
		snFieldName,
		snFieldVal,
		snFieldElement;
	var responseArr = [];
	var fileName = 'sn-data-export.csv';
	var mapObj = getMapObjectFromURL(request);

	if (
		!mapObj.hasOwnProperty('table_name') ||
		!mapObj.hasOwnProperty('columns')
	) {
		throw new Error(
			'Unable to parse map object. Map must be provided as a URI parameter with the ' +
			'name "map". Map URI parameter must be equal to a JSON object with a node ' +
			'called "table_name" with the name of the table from which you\'d like to pull ' +
			'the returned data, and an a node called "columns" which consists of an array ' +
			'of objects, each with two nodes: "destination_column_name" and ' +
			'"source_column_name".'
		);
	}

	tableName = mapObj.table_name.toString();
	columnHeaders = getHeadersFromMap(mapObj);
	//Push the column headers into the response array as the first element, in CSV format.
	responseArr.push(columnHeaders.join(','));

	if (!gs.tableExists(tableName)) {
		throw new Error(
			'Table with name ' + tableName + ' does not exist in ServiceNow, or is not ' +
			'accessible. Are you sure you\'ve entered the table name and not the label?'
		);
	}

	grComputer = new GlideRecord(tableName);

	tableQuery = (mapObj.hasOwnProperty('table_query')) ? mapObj.table_query.toString() : '';
	queryLimit = parseInt(mapObj.query_limit);

	//If query is provided, add it. Ditto for record query limit.
	if (tableQuery) {
		grComputer.addEncodedQuery(tableQuery);
	}
	if (queryLimit && queryLimit > 0) {
		grComputer.setLimit(queryLimit);
	}

	grComputer.query();

	//Here be dragons
	while (grComputer.next()) {
		//Check if user can read the found record
		if (!grComputer.canRead()) {
			gs.warn(
				'CSV Export: Record with sys_id ' + grComputer.getValue('sys_id') +
				' in table "' + tableName + '" cannot be read by the current user (' +
				gs.getUserID() + '). Skipping this record, and continuing to the next one.'
			);
			continue;
		}

		currentRow = [];

		//For each column in the map object...
		for (i = 0; i < mapObj.columns.length; i++) {
			//If map for this column is malformed, throw an error and halt.
			if (!mapObj.columns[i].hasOwnProperty('source_column_name')) {
				throw new Error(
					'CSV Export: One or more columns in the export map object is missing the ' +
					'"source_column_name" property. The export process must abort.'
				);
			}
			//Get the next field name to work on
			snFieldName = mapObj.columns[i].source_column_name.toString();
			snFieldElement = grComputer.getElement(snFieldName); //Object reference

			//If user can read the value of the specified column, get it. If not, log a warning
			// but continue anyway with a blank value for this column.
			if (
				grComputer.isValidField(snFieldName.split('.')[0]) &&
				snFieldElement.canRead()
			) {
				/*
					NOTE: We are using .getElement().toString() here, instead of simply .getValue(),
					 because the former method supports arbitrarily dot-walking into several layers
					 of data, such as "assigned_to.manager.department.id" to get the assignee's
					 manager's department ID, for example.
				 */
				snFieldVal = snFieldElement.toString();
			} else {
				snFieldVal = '';
				gs.warn(
					'CSV Export: API user ' + gs.getUserID() + ' is unable to read the ' +
					'column ' + snFieldName + ' from the record in table ' + tableName +
					' with sys_id ' + grComputer.getValue('sys_id') + '. This could ' +
					'be because the field does not exist, or because the service account ' +
					'cannot read this field from the database. Exporting a blank value for ' +
					'this field, and continuing with export.'
				);
			}
			//If all is well, push the escaped value of the specified field into currentRow.
			//currentRow will be joined at the end of this for loop, at the bottom of the while.
			currentRow.push(
				escapeValueForCSV(snFieldVal)
			);
		}

		//Join the current row into csv format, and push that value into the response array.
		responseArr.push(currentRow.join(','));
	}

	response.setHeader('Content-Type', 'text/csv');
	response.setHeader('Content-disposition', 'attachment; filename=' + fileName);
	streamWriter = response.getStreamWriter();
	//Join the response array with a line-break between each comma-delimited row and write response.
	streamWriter.writeString(responseArr.join('\n'));

	//Helper functions

	function escapeValueForCSV(fieldVal) {
		//Escape quotes.
		if (fieldVal.indexOf('"') >= 0) {
			fieldVal = fieldVal.replaceAll('"', '""');
		}

		//upcoming_feature: Escape commas won't be necessary once Tanium can handle quoted csv values
		if (fieldVal.indexOf(',')) {
			//fieldVal = fieldVal.replaceAll(',', '","');
			//Replace all commas with "turned comma" (U+2E32),
			fieldVal = fieldVal.replaceAll(',', ';');
		}


		//Wrap field value in quotes (eliminates need to escape commas/new-line characters).
		//fieldVal = '"' + fieldVal + '"';

		return fieldVal;
	}

	function getMapObjectFromURL(request) {
		var mapObj;
		try {
			mapObj = request.queryParams['map'];
			mapObj = mapObj[0];
			mapObj = JSON.parse(mapObj);
		} catch (ex) {
			throw new Error(
				'Unable to parse map object. Map must be provided as a URI parameter with the ' +
				'name "map". Map URI parameter must be equal to a JSON object with a node ' +
				'called "table_name" with the name of the table from which you\'d like to pull ' +
				'the returned data, and an a node called "columns" which consists of an array ' +
				'of objects, each with two nodes: "destination_column_name" and ' +
				'"source_column_name". \n' +
				'Error: ' + ex.message
			);
		}
		return mapObj;
	}

	/**
	 * Parse out an array of headers from the map object passed into this SRAPI from the
	 *  URI parameter "map".
	 * @param {Object} mapObj
	 * @return {*[]} An array of Strings representing the names of the columns in the CSV that
	 * should be output from this SRAPI.
	 */
	function getHeadersFromMap(mapObj) {
		var i;
		var headersArr = [];
		var columns = mapObj.columns;

		for (i = 0; i < columns.length; i++) {
			//upcoming_feature: Uncomment the first line and remove the second once Tanium can support quoted CSV values
			//headersArr.push('"' + columns[i].destination_column_name.toString() + '"');
			headersArr.push(columns[i].destination_column_name.toString());
		}

		return headersArr;
	}

	/*
	DOCUMENTATION:
		https://snprotips.com/blog/2022/2/7/how-to-return-a-csv-file-from-a-servicenow-scripted-rest-api

	Example request URL:
		https://${USERNAME}:${PASSWORD}@${INSTANCE}.service-now.com/api/x_taniu_tan_core/v1/get_records_as_csv?map=%7B%20%22table_name%22%20%3A%20%22incident%22%2C%20%22table_query%22%20%3A%20%22assigned_to.managerISNOTEMPTY%22%2C%20%22query_limit%22%20%3A%20100%2C%20%22columns%22%20%3A%20%5B%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20ID%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20mame%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.name%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20manager%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.manager%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20manager%20email%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.manager.email%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22INC%20number%22%2C%20%22source_column_name%22%20%3A%20%22number%22%20%7D%20%5D%20%7D
	 */

	/*
	Fully expanded object in the example URL above:
	{
		"table_name" : "incident",
		"table_query" : "assigned_to.manager.emailISNOTEMPTY",
		"query_limit" : 100,
		"columns" : [
			{
				"destination_column_name" : "Assignee ID",
				"source_column_name" : "assigned_to"
			},
			{
				"destination_column_name" : "Assignee mame",
				"source_column_name" : "assigned_to.name"
			},
			{
				"destination_column_name" : "Assignee manager",
				"source_column_name" : "assigned_to.manager.name"
			},
			{
				"destination_column_name" : "Assignee manager email",
				"source_column_name" : "assigned_to.manager.email"
			},
			{
				"destination_column_name" : "INC number",
				"source_column_name" : "number"
			}
		]
	}
	*/
})(request, response);
